// ── Toast ─────────────────────────────────────────────────────────────────────
const Toast = ({ msg, onDone }) => {
  useEffect(() => { const t = setTimeout(onDone, 2800); return () => clearTimeout(t); }, []);
  return (
    <div style={{ position:"fixed", bottom:30, left:"50%", transform:"translateX(-50%)", background:BRAND.dark, color:"#fff", padding:"14px 28px", borderRadius:14, fontSize:14, fontWeight:600, boxShadow:"0 8px 32px rgba(0,0,30,.25)", zIndex:9999, animation:"fadein .3s", whiteSpace:"nowrap" }}>
      ✓ {msg}
      <style>{`@keyframes fadein{from{opacity:0;transform:translateX(-50%) translateY(12px)}to{opacity:1;transform:translateX(-50%) translateY(0)}}`}</style>
    </div>
  );
};

