// SCREEN: LOGIN
// ══════════════════════════════════════════════════════════════════════════════
const LoginScreen = ({ onLogin }) => {
  const [usuario, setUsuario] = useState("");
  const [senha, setSenha] = useState("");
  const [showSenha, setShowSenha] = useState(false);
  const [erro, setErro] = useState("");
  const [loading, setLoading] = useState(false);

  const handleLogin = async () => {
    if (!usuario) { setErro("Selecione seu nome."); return; }
    if (!senha) { setErro("Digite a senha."); return; }
    setErro(""); setLoading(true);
    await new Promise(r => setTimeout(r, 400));

    // Admin
    if (usuario === ADMIN_USER && senha === ADMIN_SENHA) {
      onLogin({ nome: "Administrador", cargo: "Admin", isAdmin: true, foto: null });
      setLoading(false); return;
    }

    // Buscar usuário no Supabase
    const { data, error } = await supabase.from("usuarios").select("*").eq("nome", usuario).single();
    if (error || !data) { setErro("Usuário não encontrado."); setLoading(false); return; }
    if (!data.ativo) { setErro("Usuário inativo. Contate o administrador."); setLoading(false); return; }
    if (data.senha !== senha) { setErro("Senha incorreta."); setLoading(false); return; }

    onLogin({ ...data, isAdmin: false });
    setLoading(false);
  };

  return (
    <div style={{ minHeight:"100vh", background:BRAND.bg, display:"flex", flexDirection:"column", alignItems:"center", justifyContent:"center", padding:"24px 16px", fontFamily:"'Instrument Sans', sans-serif" }}>
      <div style={{ width:"100%", maxWidth:380 }}>
        {/* Logo */}
        <div style={{ textAlign:"center", marginBottom:40 }}>
          <Logo size={90} />
          <p style={{ margin:"12px 0 0", fontSize:14, color:"#6b7280" }}>Gestão de Leads e Visitantes</p>
        </div>

        {/* Card */}
        <div style={{ background:"#fff", borderRadius:20, padding:"32px 24px", boxShadow:"0 4px 24px rgba(0,0,0,.08)", border:"1px solid #e5e7eb" }}>
          <h2 style={{ margin:"0 0 24px", fontSize:20, fontWeight:700, color:"#111827" }}>Entrar</h2>

          {/* Usuário */}
          <div style={{ marginBottom:16 }}>
            <label style={{ display:"block", fontSize:13, fontWeight:600, color:"#374151", marginBottom:6 }}>Quem é você?</label>
            <div style={{ position:"relative" }}>
              <select value={usuario} onChange={e => { setUsuario(e.target.value); setErro(""); }}
                style={{ ...fieldStyle, appearance:"none", paddingRight:36, color: usuario ? "#111827" : "#9ca3af" }}>
                <option value="">Selecionar nome...</option>
                <option value="moni">moni (Admin)</option>
                {USUARIOS.map(u => <option key={u} value={u}>{u}</option>)}
              </select>
              <span style={{ position:"absolute", right:12, top:"50%", transform:"translateY(-50%)", pointerEvents:"none", color:"#6b7280" }}>▾</span>
            </div>
          </div>

          {/* Senha */}
          <div style={{ marginBottom:20 }}>
            <label style={{ display:"block", fontSize:13, fontWeight:600, color:"#374151", marginBottom:6 }}>Senha</label>
            <div style={{ position:"relative" }}>
              <input type={showSenha ? "text" : "password"} value={senha}
                onChange={e => { setSenha(e.target.value); setErro(""); }}
                placeholder="Digite sua senha"
                onKeyDown={e => e.key === "Enter" && handleLogin()}
                style={{ ...fieldStyle, paddingRight:44 }} onFocus={focusStyle} onBlur={blurStyle} />
              <button onClick={() => setShowSenha(p => !p)} style={{ position:"absolute", right:12, top:"50%", transform:"translateY(-50%)", background:"none", border:"none", cursor:"pointer", color:"#9ca3af", padding:0 }}>
                {showSenha
                  ? <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M17.94 17.94A10.07 10.07 0 0 1 12 20c-7 0-11-8-11-8a18.45 18.45 0 0 1 5.06-5.94M9.9 4.24A9.12 9.12 0 0 1 12 4c7 0 11 8 11 8a18.5 18.5 0 0 1-2.16 3.19m-6.72-1.07a3 3 0 1 1-4.24-4.24"/><line x1="1" y1="1" x2="23" y2="23"/></svg>
                  : <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M1 12s4-8 11-8 11 8 11 8-4 8-11 8-11-8-11-8z"/><circle cx="12" cy="12" r="3"/></svg>
                }
              </button>
            </div>
          </div>

          {erro && (
            <div style={{ background:"#fef2f2", border:"1px solid #fecaca", borderRadius:10, padding:"10px 14px", marginBottom:16, fontSize:13, color:"#dc2626", fontWeight:500 }}>
              {erro}
            </div>
          )}

          <button onClick={handleLogin} disabled={loading}
            style={{ width:"100%", height:50, borderRadius:12, border:"none", background:BRAND.gradient, color:"#fff", fontWeight:700, fontSize:15, cursor:loading ? "not-allowed" : "pointer", opacity:loading ? .7 : 1, transition:"opacity .15s", fontFamily:"inherit", boxShadow:"0 4px 14px rgba(26,47,214,.3)", display:"flex", alignItems:"center", justifyContent:"center", gap:8 }}>
            {loading ? "Entrando..." : "Entrar"}
          </button>
        </div>
        <p style={{ textAlign:"center", fontSize:12, color:"#9ca3af", marginTop:20 }}>Senha padrão: <strong>moni</strong></p>
      </div>
    </div>
  );
};

