// SCREEN: MEU PERFIL
// ══════════════════════════════════════════════════════════════════════════════
const PerfilScreen = ({ onBack, usuario, onUpdate }) => {
  const [senhaAtual, setSenhaAtual] = useState("");
  const [novaSenha, setNovaSenha] = useState("");
  const [confirmSenha, setConfirmSenha] = useState("");
  const [foto, setFoto] = useState(usuario.foto || null);
  const [cargo, setCargo] = useState(usuario.cargo || "");
  const [saving, setSaving] = useState(false);
  const [erro, setErro] = useState("");
  const [ok, setOk] = useState("");
  const fileRef = useRef(null);

  const handleFoto = (e) => {
    const file = e.target.files?.[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onload = ev => setFoto(ev.target.result);
    reader.readAsDataURL(file);
  };

  const salvarSenha = async () => {
    setErro(""); setOk("");
    if (!senhaAtual || !novaSenha || !confirmSenha) { setErro("Preencha todos os campos."); return; }
    if (novaSenha !== confirmSenha) { setErro("Nova senha e confirmação não conferem."); return; }
    if (novaSenha.length < 4) { setErro("Senha deve ter ao menos 4 caracteres."); return; }
    if (senhaAtual !== usuario.senha && !(usuario.isAdmin && senhaAtual === ADMIN_SENHA)) { setErro("Senha atual incorreta."); return; }
    setSaving(true);
    if (!usuario.isAdmin) {
      const { error } = await supabase.from("usuarios").update({ senha: novaSenha, cargo, foto }).eq("nome", usuario.nome);
      if (error) { setErro("Erro ao salvar: " + error.message); setSaving(false); return; }
    }
    onUpdate({ ...usuario, senha: novaSenha, cargo, foto });
    setSenhaAtual(""); setNovaSenha(""); setConfirmSenha("");
    setOk("Senha alterada com sucesso!");
    setSaving(false);
  };

  const salvarPerfil = async () => {
    setSaving(true);
    if (!usuario.isAdmin) {
      await supabase.from("usuarios").update({ cargo, foto }).eq("nome", usuario.nome);
    }
    onUpdate({ ...usuario, cargo, foto });
    setOk("Perfil atualizado!");
    setSaving(false);
  };

  return (
    <div style={{ minHeight:"100vh", background:BRAND.bg, paddingBottom:40 }}>
      <BackBtn onClick={onBack} label="Meu Perfil" />
      <div style={{ maxWidth:480, margin:"0 auto", padding:"24px 16px 0", display:"flex", flexDirection:"column", gap:20 }}>

        {/* Foto + Nome */}
        <div style={{ background:"#fff", borderRadius:20, padding:"28px 20px", border:"1px solid #e5e7eb", textAlign:"center", boxShadow:"0 2px 8px rgba(0,0,0,.05)" }}>
          <div style={{ position:"relative", display:"inline-block", marginBottom:16 }}>
            <div onClick={() => fileRef.current?.click()} style={{ width:90, height:90, borderRadius:"50%", background: foto ? "transparent" : BRAND.gradient, display:"flex", alignItems:"center", justifyContent:"center", cursor:"pointer", overflow:"hidden", border:`3px solid ${BRAND.primary}`, boxShadow:"0 4px 12px rgba(26,47,214,.2)" }}>
              {foto
                ? <img src={foto} alt="Foto" style={{ width:"100%", height:"100%", objectFit:"cover" }} />
                : <span style={{ fontSize:32, color:"#fff", fontWeight:700 }}>{usuario.nome?.[0]?.toUpperCase()}</span>
              }
            </div>
            <div onClick={() => fileRef.current?.click()} style={{ position:"absolute", bottom:0, right:0, background:BRAND.primary, borderRadius:"50%", width:26, height:26, display:"flex", alignItems:"center", justifyContent:"center", cursor:"pointer", border:"2px solid #fff" }}>
              <svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="#fff" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round">
                <path d="M23 19a2 2 0 0 1-2 2H3a2 2 0 0 1-2-2V8a2 2 0 0 1 2-2h4l2-3h6l2 3h4a2 2 0 0 1 2 2z"/><circle cx="12" cy="13" r="4"/>
              </svg>
            </div>
            <input ref={fileRef} type="file" accept="image/*" onChange={handleFoto} style={{ display:"none" }} />
          </div>
          <h2 style={{ margin:"0 0 4px", fontSize:20, fontWeight:700, color:"#111827" }}>{usuario.nome}</h2>
          <p style={{ margin:0, fontSize:13, color:"#6b7280" }}>{usuario.isAdmin ? "Administrador" : (cargo || "Equipe Moni")}</p>

          {!usuario.isAdmin && (
            <div style={{ marginTop:16, textAlign:"left" }}>
              <label style={{ fontSize:13, fontWeight:600, color:"#374151", display:"block", marginBottom:6 }}>Cargo</label>
              <input value={cargo} onChange={e => setCargo(e.target.value)} placeholder="Ex: Consultor, Diretor..." style={fieldStyle} onFocus={focusStyle} onBlur={blurStyle} />
            </div>
          )}

          <button onClick={salvarPerfil} disabled={saving} style={{ marginTop:16, padding:"10px 24px", borderRadius:10, border:"none", background:BRAND.gradient, color:"#fff", fontWeight:600, fontSize:13, cursor:"pointer", fontFamily:"inherit" }}>
            Salvar foto e cargo
          </button>
        </div>

        {/* Alterar senha */}
        <div style={{ background:"#fff", borderRadius:20, padding:"24px 20px", border:"1px solid #e5e7eb", boxShadow:"0 2px 8px rgba(0,0,0,.05)" }}>
          <h3 style={{ margin:"0 0 20px", fontSize:15, fontWeight:700, color:"#111827" }}>Alterar Senha</h3>
          <div style={{ display:"flex", flexDirection:"column", gap:12 }}>
            <div>
              <label style={{ fontSize:13, fontWeight:500, color:"#374151", display:"block", marginBottom:6 }}>Senha atual</label>
              <input type="password" value={senhaAtual} onChange={e => { setSenhaAtual(e.target.value); setErro(""); }} placeholder="Senha atual" style={fieldStyle} onFocus={focusStyle} onBlur={blurStyle} />
            </div>
            <div>
              <label style={{ fontSize:13, fontWeight:500, color:"#374151", display:"block", marginBottom:6 }}>Nova senha</label>
              <input type="password" value={novaSenha} onChange={e => setNovaSenha(e.target.value)} placeholder="Nova senha" style={fieldStyle} onFocus={focusStyle} onBlur={blurStyle} />
            </div>
            <div>
              <label style={{ fontSize:13, fontWeight:500, color:"#374151", display:"block", marginBottom:6 }}>Confirmar nova senha</label>
              <input type="password" value={confirmSenha} onChange={e => setConfirmSenha(e.target.value)} placeholder="Confirmar senha" style={fieldStyle} onFocus={focusStyle} onBlur={blurStyle} />
            </div>
          </div>

          {erro && <div style={{ background:"#fef2f2", border:"1px solid #fecaca", borderRadius:10, padding:"10px 14px", marginTop:14, fontSize:13, color:"#dc2626" }}>{erro}</div>}
          {ok && <div style={{ background:"#f0fdf4", border:"1px solid #86efac", borderRadius:10, padding:"10px 14px", marginTop:14, fontSize:13, color:"#16a34a", fontWeight:600 }}>✓ {ok}</div>}

          <button onClick={salvarSenha} disabled={saving} style={{ width:"100%", height:48, marginTop:16, borderRadius:12, border:"none", background:BRAND.gradient, color:"#fff", fontWeight:600, fontSize:15, cursor:saving ? "not-allowed" : "pointer", opacity:saving ? .7 : 1, fontFamily:"inherit", boxShadow:"0 4px 14px rgba(26,47,214,.25)" }}>
            {saving ? "Salvando..." : "Alterar Senha"}
          </button>
        </div>
      </div>
    </div>
  );
};

