// SCREEN: REGISTRAR VISITANTE
// ══════════════════════════════════════════════════════════════════════════════
const VisitanteScreen = ({ onBack, onSave, usuario }) => {
  const empty = { nome:"", empresa:"", cargo:"", whatsapp:"", obs:"" };
  const [f, setF] = useState(empty);
  const [saving, setSaving] = useState(false);
  const [scanning, setScanning] = useState(false);
  const [scanPreview, setScanPreview] = useState(null);
  const [scanStatus, setScanStatus] = useState("");
  const fileInputRef = useRef(null);
  const set = k => e => setF(p => ({ ...p, [k]: e.target.value }));

  const save = async (reset) => {
    if (!f.nome.trim()) { alert("Informe o nome do visitante."); return; }
    setSaving(true);
    await onSave(f, reset);
    setSaving(false);
    if (reset) { setF(empty); setScanPreview(null); setScanStatus(""); }
  };

  const handleScan = async (e) => {
    const file = e.target.files?.[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onload = ev => setScanPreview(ev.target.result);
    reader.readAsDataURL(file);
    setScanning(true); setScanStatus("loading");
    try {
      const base64 = await new Promise((res, rej) => {
        const r = new FileReader();
        r.onload = () => res(r.result.split(",")[1]);
        r.onerror = rej;
        r.readAsDataURL(file);
      });
      const response = await fetch("https://api.anthropic.com/v1/messages", {
        method:"POST",
        headers:{"Content-Type":"application/json"},
        body:JSON.stringify({
          model:"claude-sonnet-4-20250514", max_tokens:300,
          messages:[{ role:"user", content:[
            { type:"image", source:{ type:"base64", media_type: file.type || "image/jpeg", data: base64 } },
            { type:"text", text:`Analise esta credencial de evento e extraia as informações visíveis. Responda SOMENTE com JSON válido sem markdown: {"nome":"","empresa":"","cargo":""}` }
          ]}]
        })
      });
      const data = await response.json();
      const parsed = JSON.parse(data.content?.[0]?.text?.replace(/\`\`\`json|\`\`\`/g,"").trim() || "{}");
      setF(prev => ({ ...prev, nome: parsed.nome || prev.nome, empresa: parsed.empresa || prev.empresa, cargo: parsed.cargo || prev.cargo }));
      setScanStatus("success");
    } catch {
      setScanStatus("error");
    } finally {
      setScanning(false);
      if (fileInputRef.current) fileInputRef.current.value = "";
    }
  };

  return (
    <div style={{ minHeight:"100vh", background:BRAND.bg, paddingBottom:40 }}>
      <BackBtn onClick={onBack} label="Registrar Visitante" />
      <div style={{ maxWidth:512, margin:"0 auto", padding:"24px 16px 0", display:"flex", flexDirection:"column", gap:20 }}>

        {/* Scan */}
        <div style={{ background:"#fff", border:`2px dashed ${scanStatus==="success" ? "#86efac" : BRAND.primary}`, borderRadius:16, padding:"20px 16px", display:"flex", flexDirection:"column", gap:14, transition:"border-color .3s" }}>
          <div style={{ display:"flex", alignItems:"center", gap:10 }}>
            <div style={{ background:"rgba(26,47,214,.08)", borderRadius:10, width:38, height:38, display:"flex", alignItems:"center", justifyContent:"center", flexShrink:0 }}>
              <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke={BRAND.primary} strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
                <path d="M23 19a2 2 0 0 1-2 2H3a2 2 0 0 1-2-2V8a2 2 0 0 1 2-2h4l2-3h6l2 3h4a2 2 0 0 1 2 2z"/><circle cx="12" cy="13" r="4"/>
              </svg>
            </div>
            <div>
              <p style={{ margin:0, fontWeight:700, fontSize:14, color:"#111827" }}>Escanear Credencial</p>
              <p style={{ margin:0, fontSize:12, color:"#6b7280", marginTop:1 }}>Tire uma foto do crachá para preencher automaticamente</p>
            </div>
          </div>
          {scanPreview && (
            <div style={{ position:"relative", borderRadius:10, overflow:"hidden", maxHeight:180 }}>
              <img src={scanPreview} alt="Credencial" style={{ width:"100%", objectFit:"cover", borderRadius:10, display:"block" }} />
              {scanning && (
                <div style={{ position:"absolute", inset:0, background:"rgba(255,255,255,.8)", display:"flex", flexDirection:"column", alignItems:"center", justifyContent:"center", gap:10 }}>
                  <Spin />
                  <p style={{ margin:0, fontSize:13, color:BRAND.primary, fontWeight:600 }}>Lendo credencial...</p>
                </div>
              )}
            </div>
          )}
          {scanStatus==="success" && !scanning && (
            <div style={{ display:"flex", alignItems:"center", gap:8, background:"#f0fdf4", border:"1px solid #86efac", borderRadius:10, padding:"10px 14px" }}>
              <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="#16a34a" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"><path d="M22 11.08V12a10 10 0 1 1-5.93-9.14"/><polyline points="22 4 12 14.01 9 11.01"/></svg>
              <p style={{ margin:0, fontSize:13, color:"#16a34a", fontWeight:600 }}>Credencial lida! Confira os campos abaixo.</p>
            </div>
          )}
          {scanStatus==="error" && !scanning && (
            <div style={{ display:"flex", alignItems:"center", gap:8, background:"#fef2f2", border:"1px solid #fecaca", borderRadius:10, padding:"10px 14px" }}>
              <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="#dc2626" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"><circle cx="12" cy="12" r="10"/><line x1="12" y1="8" x2="12" y2="12"/><line x1="12" y1="16" x2="12.01" y2="16"/></svg>
              <p style={{ margin:0, fontSize:13, color:"#dc2626", fontWeight:600 }}>Não foi possível ler. Preencha manualmente.</p>
            </div>
          )}
          <input ref={fileInputRef} type="file" accept="image/*" capture="environment" onChange={handleScan} style={{ display:"none" }} />
          <button onClick={() => fileInputRef.current?.click()} disabled={scanning}
            style={{ height:46, borderRadius:12, border:`1.5px solid ${BRAND.primary}`, background:scanning ? "#f9fafb" : "rgba(26,47,214,.06)", color:scanning ? "#9ca3af" : BRAND.primary, fontWeight:600, fontSize:14, cursor:scanning ? "not-allowed" : "pointer", display:"flex", alignItems:"center", justifyContent:"center", gap:8, fontFamily:"inherit" }}>
            <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M23 19a2 2 0 0 1-2 2H3a2 2 0 0 1-2-2V8a2 2 0 0 1 2-2h4l2-3h6l2 3h4a2 2 0 0 1 2 2z"/><circle cx="12" cy="13" r="4"/></svg>
            {scanning ? "Processando..." : scanPreview ? "Escanear novamente" : "Abrir câmera"}
          </button>
        </div>

        {[["Nome","nome","Nome completo",true], ["Empresa","empresa","Nome da empresa",false], ["Cargo","cargo","Cargo ou função",false]].map(([lbl,key,ph,req]) => (
          <div key={key} style={{ display:"flex", flexDirection:"column", gap:6 }}>
            <label style={{ fontSize:13, fontWeight:500, color:"#374151" }}>{lbl} {req && <span style={{ color:"#ef4444" }}>*</span>}</label>
            <input value={f[key]} onChange={set(key)} placeholder={ph} style={fieldStyle} onFocus={focusStyle} onBlur={blurStyle} />
          </div>
        ))}
        <div style={{ display:"flex", flexDirection:"column", gap:6 }}>
          <label style={{ fontSize:13, fontWeight:500, color:"#374151" }}>WhatsApp</label>
          <input value={f.whatsapp} onChange={e => setF(p => ({ ...p, whatsapp: formatPhone(e.target.value) }))} placeholder="(00) 00000-0000" type="tel" style={fieldStyle} onFocus={focusStyle} onBlur={blurStyle} />
        </div>
        <div style={{ display:"flex", flexDirection:"column", gap:6 }}>
          <label style={{ fontSize:13, fontWeight:500, color:"#374151" }}>Observação</label>
          <textarea value={f.obs} onChange={set("obs")} placeholder="Anotações sobre a visita..." rows={4} style={{ ...fieldStyle, height:"auto", minHeight:100, padding:"12px 14px", resize:"none", fontFamily:"inherit" }} onFocus={focusStyle} onBlur={blurStyle} />
        </div>

        <div style={{ paddingTop:8, display:"flex", flexDirection:"column", gap:12 }}>
          <button onClick={() => save(false)} disabled={saving} style={{ width:"100%", height:48, borderRadius:12, border:"none", cursor:saving ? "not-allowed" : "pointer", background:BRAND.gradient, color:"#fff", fontWeight:600, fontSize:15, display:"flex", alignItems:"center", justifyContent:"center", gap:8, opacity:saving ? .7 : 1, fontFamily:"inherit", boxShadow:"0 4px 14px rgba(26,47,214,.25)" }}>
            <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M22 11.08V12a10 10 0 1 1-5.93-9.14"/><polyline points="22 4 12 14.01 9 11.01"/></svg>
            {saving ? "Salvando..." : "Salvar"}
          </button>
          <button onClick={() => save(true)} disabled={saving} style={{ width:"100%", height:48, borderRadius:12, border:"1px solid #e5e7eb", cursor:saving ? "not-allowed" : "pointer", background:"#f9fafb", color:"#374151", fontWeight:600, fontSize:15, opacity:saving ? .6 : 1, fontFamily:"inherit" }}>
            Salvar e Novo
          </button>
        </div>
      </div>
    </div>
  );
};

// ══════════════════════════════════════════════════════════════════════════════
// SCREEN: POTENCIAL CLIENTE (LEAD)
// ══════════════════════════════════════════════════════════════════════════════
const LeadScreen = ({ onBack, onSave, usuario }) => {
  const empty = { atendente: usuario.nome || "", nome:"", whatsapp:"", email:"", empresa:"", cargo:"", cidade_estado:"", qtd_contas:"", qtd_portarias:"", software_atual:"", software_outro:"", segmento:[], interesse:[], temperatura:"", obs:"" };
  const [f, setF] = useState(empty);
  const [saving, setSaving] = useState(false);
  const set = k => e => setF(p => ({ ...p, [k]: e.target.value }));
  const toggleArr = (k, v) => setF(p => ({ ...p, [k]: p[k].includes(v) ? p[k].filter(x => x !== v) : [...p[k], v] }));

  const save = async (reset) => {
    if (!f.nome.trim()) { alert("Informe o nome do lead."); return; }
    setSaving(true);
    await onSave(f, reset);
    setSaving(false);
    if (reset) setF(empty);
  };

  const sectionLabel = txt => <div style={{ fontSize:11, fontWeight:700, letterSpacing:"0.12em", color:"#9ca3af", marginBottom:4, marginTop:4 }}>{txt}</div>;
  const card = content => <div style={{ background:"#fff", border:"1px solid #e5e7eb", borderRadius:16, padding:"16px", boxShadow:"0 1px 3px rgba(0,0,0,.04)" }}>{content}</div>;
  const fieldBlock = (lbl, req, input) => (
    <div style={{ display:"flex", flexDirection:"column", gap:6, marginBottom:14 }}>
      <label style={{ fontSize:13, fontWeight:500, color:"#374151" }}>{lbl} {req && <span style={{ color:"#ef4444" }}>*</span>}</label>
      {input}
    </div>
  );
  const inp = (k, ph, type="text") => <input value={f[k]} onChange={set(k)} placeholder={ph} type={type} style={fieldStyle} onFocus={focusStyle} onBlur={blurStyle} />;
  const selField = (k, ph, opts) => (
    <div style={{ position:"relative" }}>
      <select value={f[k]} onChange={set(k)} style={{ ...fieldStyle, appearance:"none", paddingRight:36, color:f[k] ? "#111827" : "#9ca3af" }}>
        <option value="">{ph}</option>
        {opts.map(o => <option key={o} value={o}>{o}</option>)}
      </select>
      <span style={{ position:"absolute", right:12, top:"50%", transform:"translateY(-50%)", pointerEvents:"none", color:"#6b7280" }}>▾</span>
    </div>
  );
  const chips = (k, opts, colorSel, colorSelBg) => (
    <div style={{ display:"flex", flexWrap:"wrap", gap:8 }}>
      {opts.map(item => {
        const sel = f[k].includes(item);
        return <div key={item} onClick={() => toggleArr(k, item)} style={{ padding:"7px 14px", borderRadius:20, border:`1.5px solid ${sel ? colorSel : "#e5e7eb"}`, background: sel ? colorSelBg : "#fff", color: sel ? colorSel : "#6b7280", fontSize:13, fontWeight: sel ? 600 : 400, cursor:"pointer", transition:"all .15s" }}>{sel && "✓ "}{item}</div>;
      })}
    </div>
  );

  return (
    <div style={{ minHeight:"100vh", background:BRAND.bg, paddingBottom:40 }}>
      <BackBtn onClick={onBack} label="Potencial Cliente" />
      <div style={{ maxWidth:560, margin:"0 auto", padding:"20px 16px 0", display:"flex", flexDirection:"column", gap:12 }}>

        {sectionLabel("VENDEDOR")}
        {card(fieldBlock("Quem está atendendo", true, selField("atendente", "Selecionar atendente", ATENDENTES_LEAD)))}

        {sectionLabel("DADOS DO LEAD")}
        {card(<>
          {fieldBlock("Nome Completo", true, inp("nome", "Nome completo"))}
          {fieldBlock("E-mail", false, inp("email", "email@empresa.com", "email"))}
          {fieldBlock("WhatsApp", false, <input value={f.whatsapp} onChange={e => setF(p => ({ ...p, whatsapp: formatPhone(e.target.value) }))} placeholder="(00) 00000-0000" type="tel" style={fieldStyle} onFocus={focusStyle} onBlur={blurStyle} />)}
          {fieldBlock("Empresa", false, inp("empresa", "Nome da empresa"))}
          {fieldBlock("Cargo", false, inp("cargo", "Ex: Diretor, Gerente..."))}
          {fieldBlock("Cidade/Estado", false, inp("cidade_estado", "Ex: São Paulo/SP"))}
        </>)}

        {sectionLabel("QUALIFICAÇÃO")}
        {card(<>
          {fieldBlock("Quantidade de contas monitoradas", false, inp("qtd_contas", "Ex: 500"))}
          {fieldBlock("Quantidade de portarias remotas", false, inp("qtd_portarias", "Ex: 10"))}
          {fieldBlock("Software utilizado atualmente", false,
            <div style={{ display:"flex", flexDirection:"column", gap:10 }}>
              {selField("software_atual", "Selecionar software...", SOFTWARES)}
              {f.software_atual === "Outros" && <input value={f.software_outro} onChange={e => setF(p => ({ ...p, software_outro: e.target.value }))} placeholder="Qual software utiliza?" style={fieldStyle} onFocus={focusStyle} onBlur={blurStyle} />}
            </div>
          )}
          <div style={{ display:"flex", flexDirection:"column", gap:8 }}>
            <label style={{ fontSize:13, fontWeight:500, color:"#374151" }}>Segmento da empresa</label>
            {chips("segmento", SEGMENTOS, BRAND.primary, "rgba(26,47,214,.08)")}
          </div>
        </>)}

        {sectionLabel("INTERESSE")}
        {card(<>
          <div style={{ display:"flex", flexDirection:"column", gap:8, marginBottom:14 }}>
            <label style={{ fontSize:13, fontWeight:500, color:"#374151" }}>Interesse em</label>
            {chips("interesse", INTERESSES, BRAND.primary, "rgba(26,47,214,.08)")}
          </div>
          <div style={{ display:"flex", flexDirection:"column", gap:8 }}>
            <label style={{ fontSize:13, fontWeight:500, color:"#374151" }}>Temperatura</label>
            <div style={{ display:"flex", gap:8, flexWrap:"wrap" }}>
              {Object.entries(TEMP_CONFIG).map(([key, cfg]) => {
                const sel = f.temperatura === key;
                return <div key={key} onClick={() => setF(p => ({ ...p, temperatura: sel ? "" : key }))} style={{ display:"flex", alignItems:"center", gap:6, padding:"7px 14px", borderRadius:20, cursor:"pointer", transition:"all .15s", border:`1.5px solid ${sel ? cfg.border : "#e5e7eb"}`, background: sel ? cfg.bg : "#fff", fontSize:13, fontWeight: sel ? 600 : 400, color: sel ? cfg.text : "#6b7280" }}>{cfg.emoji} {key}</div>;
              })}
            </div>
          </div>
        </>)}

        {sectionLabel("OBSERVAÇÃO")}
        {card(<div style={{ display:"flex", flexDirection:"column", gap:6 }}>
          <label style={{ fontSize:13, fontWeight:500, color:"#374151" }}>Informações adicionais</label>
          <textarea value={f.obs} onChange={set("obs")} placeholder="Anotações relevantes sobre o lead..." rows={4} style={{ ...fieldStyle, height:"auto", minHeight:100, padding:"12px 14px", resize:"none", fontFamily:"inherit" }} onFocus={focusStyle} onBlur={blurStyle} />
        </div>)}

        <div style={{ paddingTop:8, display:"flex", flexDirection:"column", gap:12 }}>
          <button onClick={() => save(false)} disabled={saving} style={{ width:"100%", height:48, borderRadius:12, border:"none", cursor:saving ? "not-allowed" : "pointer", background:BRAND.gradient, color:"#fff", fontWeight:600, fontSize:15, display:"flex", alignItems:"center", justifyContent:"center", gap:8, opacity:saving ? .7 : 1, fontFamily:"inherit", boxShadow:"0 4px 14px rgba(26,47,214,.25)" }}>
            <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M22 11.08V12a10 10 0 1 1-5.93-9.14"/><polyline points="22 4 12 14.01 9 11.01"/></svg>
            {saving ? "Salvando..." : "Salvar"}
          </button>
          <button onClick={() => save(true)} disabled={saving} style={{ width:"100%", height:48, borderRadius:12, border:"1px solid #e5e7eb", cursor:saving ? "not-allowed" : "pointer", background:"#f9fafb", color:"#374151", fontWeight:600, fontSize:15, opacity:saving ? .6 : 1, fontFamily:"inherit" }}>
            Salvar e Novo
          </button>
        </div>
      </div>
    </div>
  );
};

// ══════════════════════════════════════════════════════════════════════════════
// SCREEN: LISTA VISITANTES
// ══════════════════════════════════════════════════════════════════════════════
const VisitantesScreen = ({ onBack, items, usuario }) => {
  const [search, setSearch] = useState("");
  const [filtroAtendente, setFiltroAtendente] = useState(usuario.isAdmin ? "todos" : usuario.nome);
  const [verTodos, setVerTodos] = useState(false);

  const filtered = items.filter(v => {
    const matchSearch = !search || v.nome?.toLowerCase().includes(search.toLowerCase()) || v.empresa?.toLowerCase().includes(search.toLowerCase());
    const atendenteFiltro = verTodos ? "todos" : filtroAtendente;
    const matchAtendente = atendenteFiltro === "todos" || v.atendente === atendenteFiltro;
    return matchSearch && matchAtendente;
  });

  const hdrs = ["Nome","Empresa","Cargo","WhatsApp","Atendido por","Observação","Data"];
  const mapper = v => [v.nome, v.empresa, v.cargo, v.whatsapp, v.atendente, v.obs, v.data_hora || ""];

  return (
    <div style={{ minHeight:"100vh", background:BRAND.bg, paddingBottom:40 }}>
      <div style={{ position:"sticky", top:0, zIndex:10, background:"rgba(255,255,255,.9)", backdropFilter:"blur(12px)", borderBottom:"1px solid #e5e7eb", padding:"12px 16px", display:"flex", alignItems:"center", gap:10 }}>
        <button onClick={onBack} style={{ background:"none", border:"none", borderRadius:8, width:34, height:34, display:"flex", alignItems:"center", justifyContent:"center", cursor:"pointer", color:"#374151", flexShrink:0 }}>
          <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="m12 19-7-7 7-7"/><path d="M19 12H5"/></svg>
        </button>
        <h1 style={{ fontSize:16, fontWeight:600, color:"#111827", margin:0, flex:1 }}>Visitantes</h1>
        <ExportMenu
          onCSV={() => exportCSV(filtered, "visitantes.csv", hdrs, mapper)}
          onXLSX={() => exportXLSX(filtered, "visitantes.csv", hdrs, mapper)}
          onPDF={() => exportPDF(filtered, "Visitantes", hdrs, mapper)}
        />
      </div>
      <div style={{ maxWidth:560, margin:"0 auto", padding:"20px 16px 0", display:"flex", flexDirection:"column", gap:14 }}>
        <div style={{ display:"flex", gap:10, flexWrap:"wrap" }}>
          <SearchInput value={search} onChange={setSearch} />
          {!verTodos && <FilterSelect value={filtroAtendente} onChange={setFiltroAtendente} options={USUARIOS} />}
        </div>
        <div style={{ display:"flex", alignItems:"center", gap:12 }}>
          <p style={{ fontSize:13, color:"#6b7280", margin:0 }}>{filtered.length} registro{filtered.length!==1?"s":""}</p>
          <button onClick={() => setVerTodos(p => !p)} style={{ background:"none", border:"none", cursor:"pointer", fontSize:12, color:BRAND.primary, fontFamily:"inherit", textDecoration:"underline", textUnderlineOffset:3 }}>
            {verTodos ? "Ver apenas meus" : "Ver todos"}
          </button>
        </div>

        {filtered.length === 0 ? <EmptyState msg="Nenhum visitante encontrado" /> :
          filtered.map((v, i) => (
            <div key={i} style={{ background:"#fff", border:"1px solid #e5e7eb", borderRadius:16, overflow:"hidden", boxShadow:"0 1px 4px rgba(0,0,0,.05)" }}>
              <div style={{ padding:"14px 16px 12px", borderBottom:"1px solid #f3f4f6", display:"flex", alignItems:"flex-start", justifyContent:"space-between", gap:10 }}>
                <div style={{ display:"flex", alignItems:"center", gap:10, minWidth:0 }}>
                  <div style={{ background:"rgba(26,47,214,.08)", borderRadius:10, width:36, height:36, display:"flex", alignItems:"center", justifyContent:"center", flexShrink:0 }}>
                    <svg width="17" height="17" viewBox="0 0 24 24" fill="none" stroke={BRAND.primary} strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M20 21v-2a4 4 0 0 0-4-4H8a4 4 0 0 0-4 4v2"/><circle cx="12" cy="7" r="4"/></svg>
                  </div>
                  <div style={{ minWidth:0 }}>
                    <p style={{ margin:0, fontWeight:700, color:"#111827", fontSize:14, overflow:"hidden", textOverflow:"ellipsis", whiteSpace:"nowrap" }}>{v.nome}</p>
                    {(v.empresa || v.cargo) && <p style={{ margin:"2px 0 0", fontSize:12, color:"#6b7280" }}>{[v.empresa, v.cargo].filter(Boolean).join(" · ")}</p>}
                  </div>
                </div>
                <div style={{ display:"flex", flexDirection:"column", alignItems:"flex-end", gap:4, flexShrink:0 }}>
                  {v.data_hora && <span style={{ fontSize:11, color:"#9ca3af", background:"#f9fafb", border:"1px solid #f3f4f6", borderRadius:8, padding:"3px 8px", whiteSpace:"nowrap" }}>{fmtDate(v.data_hora)}</span>}
                  <CopyBtn onCopy={() => copyVisitante(v)} />
                </div>
              </div>
              <div style={{ padding:"12px 16px", display:"flex", flexDirection:"column", gap:8 }}>
                {v.whatsapp && <div style={{ display:"flex", alignItems:"center", gap:8 }}><svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke={BRAND.primary} strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M22 16.92v3a2 2 0 0 1-2.18 2 19.79 19.79 0 0 1-8.63-3.07A19.5 19.5 0 0 1 4.69 13a19.79 19.79 0 0 1-3.07-8.67A2 2 0 0 1 3.6 2.18h3a2 2 0 0 1 2 1.72c.127.96.361 1.903.7 2.81a2 2 0 0 1-.45 2.11L7.91 9.91a16 16 0 0 0 6.13 6.13l.95-.95a2 2 0 0 1 2.11-.45c.907.339 1.85.573 2.81.7A2 2 0 0 1 22 16.92z"/></svg><span style={{ fontSize:13, color:"#374151" }}>{v.whatsapp}</span></div>}
                {v.atendente && <div style={{ display:"flex", alignItems:"center", gap:8 }}><svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke={BRAND.primary} strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M16 21v-2a4 4 0 0 0-4-4H6a4 4 0 0 0-4 4v2"/><circle cx="9" cy="7" r="4"/><path d="M22 21v-2a4 4 0 0 0-3-3.87"/><path d="M16 3.13a4 4 0 0 1 0 7.75"/></svg><span style={{ fontSize:13, color:"#374151" }}>Atendido por <strong>{v.atendente}</strong></span></div>}
                {v.obs && <div style={{ display:"flex", alignItems:"flex-start", gap:8, marginTop:2, paddingTop:8, borderTop:"1px solid #f3f4f6" }}><svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke={BRAND.primary} strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" style={{ marginTop:1, flexShrink:0 }}><path d="M14 2H6a2 2 0 0 0-2 2v16a2 2 0 0 0 2 2h12a2 2 0 0 0 2-2V8z"/><polyline points="14 2 14 8 20 8"/><line x1="16" y1="13" x2="8" y2="13"/><line x1="16" y1="17" x2="8" y2="17"/></svg><p style={{ margin:0, fontSize:13, color:"#6b7280", display:"-webkit-box", WebkitLineClamp:2, WebkitBoxOrient:"vertical", overflow:"hidden" }}>{v.obs}</p></div>}
              </div>
            </div>
          ))
        }
      </div>
    </div>
  );
};

// ══════════════════════════════════════════════════════════════════════════════
// SCREEN: LISTA LEADS
// ══════════════════════════════════════════════════════════════════════════════
const LeadsScreen = ({ onBack, items, usuario }) => {
  const [search, setSearch] = useState("");
  const [filtroAtendente, setFiltroAtendente] = useState(usuario.isAdmin ? "todos" : usuario.nome);
  const [verTodos, setVerTodos] = useState(false);
  const [filtroTemp, setFiltroTemp] = useState("todos");

  const filtered = items.filter(l => {
    const matchSearch = !search || l.nome?.toLowerCase().includes(search.toLowerCase()) || l.empresa?.toLowerCase().includes(search.toLowerCase());
    const atendenteFiltro = verTodos ? "todos" : filtroAtendente;
    const matchAtendente = atendenteFiltro === "todos" || l.atendente === atendenteFiltro;
    const matchTemp = filtroTemp === "todos" || l.temperatura === filtroTemp;
    return matchSearch && matchAtendente && matchTemp;
  });

  const hdrs = ["Nome","E-mail","WhatsApp","Empresa","Cargo","Cidade/Estado","Atendido por","Qtd Contas","Qtd Portarias","Software atual","Segmento","Interesse","Temperatura","Data"];
  const mapper = l => [l.nome, l.email, l.whatsapp, l.empresa, l.cargo, l.cidade_estado, l.atendente, l.qtd_contas, l.qtd_portarias, l.software_atual==="Outros"&&l.software_outro?l.software_outro:l.software_atual, (l.segmento||[]).join("; "), (l.interesse||[]).join("; "), l.temperatura, l.data_hora||""];

  return (
    <div style={{ minHeight:"100vh", background:BRAND.bg, paddingBottom:40 }}>
      <div style={{ position:"sticky", top:0, zIndex:10, background:"rgba(255,255,255,.9)", backdropFilter:"blur(12px)", borderBottom:"1px solid #e5e7eb", padding:"12px 16px", display:"flex", alignItems:"center", gap:10 }}>
        <button onClick={onBack} style={{ background:"none", border:"none", borderRadius:8, width:34, height:34, display:"flex", alignItems:"center", justifyContent:"center", cursor:"pointer", color:"#374151", flexShrink:0 }}>
          <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="m12 19-7-7 7-7"/><path d="M19 12H5"/></svg>
        </button>
        <h1 style={{ fontSize:16, fontWeight:600, color:"#111827", margin:0, flex:1 }}>Leads</h1>
        <ExportMenu
          onCSV={() => exportCSV(filtered, "leads.csv", hdrs, mapper)}
          onXLSX={() => exportXLSX(filtered, "leads.csv", hdrs, mapper)}
          onPDF={() => exportPDF(filtered, "Leads", hdrs, mapper)}
        />
      </div>
      <div style={{ maxWidth:560, margin:"0 auto", padding:"20px 16px 0", display:"flex", flexDirection:"column", gap:14 }}>
        <div style={{ display:"flex", gap:10, flexWrap:"wrap" }}>
          <SearchInput value={search} onChange={setSearch} />
          <FilterSelect value={filtroTemp} onChange={setFiltroTemp} options={["Quente","Morno","Frio"]} placeholder="Temperatura" />
        </div>
        <div style={{ display:"flex", alignItems:"center", gap:12 }}>
          <p style={{ fontSize:13, color:"#6b7280", margin:0 }}>{filtered.length} registro{filtered.length!==1?"s":""}</p>
          <button onClick={() => setVerTodos(p => !p)} style={{ background:"none", border:"none", cursor:"pointer", fontSize:12, color:BRAND.primary, fontFamily:"inherit", textDecoration:"underline", textUnderlineOffset:3 }}>
            {verTodos ? "Ver apenas meus" : "Ver todos"}
          </button>
        </div>
        {filtered.length === 0 ? <EmptyState msg="Nenhum lead encontrado" /> :
          filtered.map((l, i) => {
            const tc = TEMP_CONFIG[l.temperatura];
            return (
              <div key={i} style={{ background:"#fff", border:"1px solid #e5e7eb", borderRadius:16, overflow:"hidden", boxShadow:"0 1px 4px rgba(0,0,0,.05)" }}>
                <div style={{ padding:"14px 16px 12px", borderBottom:"1px solid #f3f4f6", display:"flex", alignItems:"flex-start", justifyContent:"space-between", gap:10 }}>
                  <div style={{ display:"flex", alignItems:"center", gap:10, minWidth:0 }}>
                    <div style={{ background:"rgba(26,47,214,.08)", borderRadius:10, width:36, height:36, display:"flex", alignItems:"center", justifyContent:"center", flexShrink:0 }}>
                      <svg width="17" height="17" viewBox="0 0 24 24" fill="none" stroke={BRAND.primary} strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><polygon points="12 2 15.09 8.26 22 9.27 17 14.14 18.18 21.02 12 17.77 5.82 21.02 7 14.14 2 9.27 8.91 8.26 12 2"/></svg>
                    </div>
                    <div style={{ minWidth:0 }}>
                      <p style={{ margin:0, fontWeight:700, color:"#111827", fontSize:14, overflow:"hidden", textOverflow:"ellipsis", whiteSpace:"nowrap" }}>{l.nome}</p>
                      {(l.empresa || l.cargo) && <p style={{ margin:"2px 0 0", fontSize:12, color:"#6b7280" }}>{[l.empresa, l.cargo].filter(Boolean).join(" · ")}</p>}
                    </div>
                  </div>
                  <div style={{ display:"flex", flexDirection:"column", alignItems:"flex-end", gap:4, flexShrink:0 }}>
                    {tc && <span style={{ fontSize:11, fontWeight:600, padding:"3px 8px", borderRadius:8, background:tc.bg, color:tc.text, border:`1px solid ${tc.border}` }}>{tc.emoji} {l.temperatura}</span>}
                    {l.data_hora && <span style={{ fontSize:11, color:"#9ca3af", background:"#f9fafb", border:"1px solid #f3f4f6", borderRadius:8, padding:"3px 8px" }}>{fmtDate(l.data_hora)}</span>}
                    <CopyBtn onCopy={() => copyLead(l)} />
                  </div>
                </div>
                <div style={{ padding:"12px 16px", display:"flex", flexDirection:"column", gap:7, borderBottom:"1px solid #f3f4f6" }}>
                  {l.whatsapp && <div style={{ display:"flex", alignItems:"center", gap:8 }}><svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke={BRAND.primary} strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M22 16.92v3a2 2 0 0 1-2.18 2 19.79 19.79 0 0 1-8.63-3.07A19.5 19.5 0 0 1 4.69 13a19.79 19.79 0 0 1-3.07-8.67A2 2 0 0 1 3.6 2.18h3a2 2 0 0 1 2 1.72c.127.96.361 1.903.7 2.81a2 2 0 0 1-.45 2.11L7.91 9.91a16 16 0 0 0 6.13 6.13l.95-.95a2 2 0 0 1 2.11-.45c.907.339 1.85.573 2.81.7A2 2 0 0 1 22 16.92z"/></svg><span style={{ fontSize:13, color:"#374151" }}>{l.whatsapp}</span></div>}
                  {l.email && <div style={{ display:"flex", alignItems:"center", gap:8 }}><svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke={BRAND.primary} strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M4 4h16c1.1 0 2 .9 2 2v12c0 1.1-.9 2-2 2H4c-1.1 0-2-.9-2-2V6c0-1.1.9-2 2-2z"/><polyline points="22,6 12,13 2,6"/></svg><span style={{ fontSize:13, color:"#374151" }}>{l.email}</span></div>}
                  {l.cidade_estado && <div style={{ display:"flex", alignItems:"center", gap:8 }}><svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke={BRAND.primary} strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M21 10c0 7-9 13-9 13s-9-6-9-13a9 9 0 0 1 18 0z"/><circle cx="12" cy="10" r="3"/></svg><span style={{ fontSize:13, color:"#374151" }}>{l.cidade_estado}</span></div>}
                  {l.atendente && <div style={{ display:"flex", alignItems:"center", gap:8 }}><svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke={BRAND.primary} strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M16 21v-2a4 4 0 0 0-4-4H6a4 4 0 0 0-4 4v2"/><circle cx="9" cy="7" r="4"/><path d="M22 21v-2a4 4 0 0 0-3-3.87"/><path d="M16 3.13a4 4 0 0 1 0 7.75"/></svg><span style={{ fontSize:13, color:"#374151" }}>Atendido por <strong>{l.atendente}</strong></span></div>}
                </div>
                {(l.software_atual || l.qtd_contas || l.qtd_portarias) && (
                  <div style={{ padding:"10px 16px", borderBottom:"1px solid #f3f4f6", display:"flex", flexWrap:"wrap", gap:12 }}>
                    {l.software_atual && <div style={{ display:"flex", alignItems:"center", gap:6 }}><svg width="13" height="13" viewBox="0 0 24 24" fill="none" stroke={BRAND.primary} strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><rect x="2" y="3" width="20" height="14" rx="2"/><path d="M8 21h8m-4-4v4"/></svg><span style={{ fontSize:12, color:"#6b7280" }}>{l.software_atual==="Outros"&&l.software_outro?l.software_outro:l.software_atual}</span></div>}
                    {l.qtd_contas && <div style={{ display:"flex", alignItems:"center", gap:6 }}><svg width="13" height="13" viewBox="0 0 24 24" fill="none" stroke={BRAND.primary} strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M17 21v-2a4 4 0 0 0-4-4H5a4 4 0 0 0-4 4v2"/><circle cx="9" cy="7" r="4"/><path d="M23 21v-2a4 4 0 0 0-3-3.87"/><path d="M16 3.13a4 4 0 0 1 0 7.75"/></svg><span style={{ fontSize:12, color:"#6b7280" }}>{l.qtd_contas} contas</span></div>}
                    {l.qtd_portarias && <div style={{ display:"flex", alignItems:"center", gap:6 }}><svg width="13" height="13" viewBox="0 0 24 24" fill="none" stroke={BRAND.primary} strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M3 9l9-7 9 7v11a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2z"/><polyline points="9 22 9 12 15 12 15 22"/></svg><span style={{ fontSize:12, color:"#6b7280" }}>{l.qtd_portarias} portarias</span></div>}
                  </div>
                )}
                {(l.segmento?.length > 0 || l.interesse?.length > 0) && (
                  <div style={{ padding:"10px 16px", display:"flex", flexDirection:"column", gap:8 }}>
                    {l.segmento?.length > 0 && (
                      <div>
                        <p style={{ margin:"0 0 5px", fontSize:10, fontWeight:700, color:"#9ca3af", textTransform:"uppercase", letterSpacing:"0.06em" }}>Segmento</p>
                        <div style={{ display:"flex", flexWrap:"wrap", gap:5 }}>{l.segmento.map(s => <span key={s} style={{ fontSize:11, fontWeight:500, padding:"3px 9px", borderRadius:20, background:"#f3f4f6", color:"#374151", border:"1px solid #e5e7eb" }}>{s}</span>)}</div>
                      </div>
                    )}
                    {l.segmento?.length > 0 && l.interesse?.length > 0 && <div style={{ height:1, background:"#f3f4f6" }} />}
                    {l.interesse?.length > 0 && (
                      <div>
                        <p style={{ margin:"0 0 5px", fontSize:10, fontWeight:700, color:"#9ca3af", textTransform:"uppercase", letterSpacing:"0.06em" }}>Interesse</p>
                        <div style={{ display:"flex", flexWrap:"wrap", gap:5 }}>{l.interesse.map(eu => <span key={eu} style={{ fontSize:11, fontWeight:500, padding:"3px 9px", borderRadius:20, background:"rgba(26,47,214,.07)", color:BRAND.primary, border:"1px solid rgba(26,47,214,.15)" }}>{eu}</span>)}</div>
                      </div>
                    )}
                  </div>
                )}
              </div>
            );
          })
        }
      </div>
    </div>
  );
};

